import style from "./nav.module.scss"
import template from './index.html'
import {NavItem} from "../../types"

export default class Nav extends HTMLElement {
  nav: HTMLElement
  scrimEle: HTMLElement
  drawer: HTMLElement
  set open(value: boolean) {
    this.setAttribute("open", value.toString())
  }
  get open(): boolean {
    const value = this.getAttribute("open")
    return value === "true" ? true : false
  }
  set collapse(value: boolean) {
    if (value) {
      this.setAttribute("collapse", value.toString())
    } else {
      this.removeAttribute("collapse")
    }
  }
  get collapse(): boolean {
    const value = this.getAttribute("collapse")
    return value === "true" ? true : false
  }
  set scrim(value: boolean) {
    this.setAttribute("scrim", value.toString())
  }
  get scrim(): boolean {
    const value = this.getAttribute("scrim")
    return value === "true" ? true : false
  }
  set active(value: boolean) {
    this.setAttribute("active", value.toString())
  }
  get active(): boolean {
    const value = this.getAttribute("active")
    return value === "true" ? true : false
  }
  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    const sheet = new CSSStyleSheet();
    sheet.replace(style);
    shadowRoot.adoptedStyleSheets = [sheet];
    shadowRoot.innerHTML = template
  }
  static get observedAttributes() {
    return ['open', 'collapse', 'scrim', 'active'];
  }
  attributeChangedCallback(name, oldValue, newValue) {
    setTimeout(() => {
      this.render()
    })
  }

  willLoad = () => {
    this.setAttribute("role", "navigation")
    this.nav = this.shadowRoot?.querySelector("nav") as HTMLElement
    this.scrimEle = this.shadowRoot?.querySelector("#scrim") as HTMLElement
    this.drawer = this.shadowRoot?.querySelector("#drawer") as HTMLElement
    !this.active && window.addEventListener("keydown", e => {
      if (e.key === "Escape" && this.open) {
        this.open = false
      }
    })
    !this.active && this.scrimEle.addEventListener("click", e => {
      if (this.open && e.target === this.scrimEle) {
        this.open = false
      }
    })
    !this.active && window.addEventListener("focusin", e => {
      if (!this.contains(document.activeElement)) {
        this.open = false
      }
    })
  }
  connectedCallback() {
    this.classList.add("hydrated")
    setTimeout(() => {
      this.willLoad()
      this.render()
    })
  }
  disconnectedCallback() {
    this.open = false
  }

  render = () => {
    if (this.open) {
      this.nav?.classList.add("visible")
      this.scrimEle?.classList.add("visible")
      this.drawer?.classList.add("open")
    } else {
      this.nav?.classList.remove("visible")
      this.scrimEle?.classList.remove("visible")
      this.drawer?.classList.remove("open")
    }
    if (this.scrim) {
      !this.nav?.contains(this.scrimEle) && this.nav?.prepend(this.scrimEle)
    } else {
      this.nav?.contains(this.scrimEle) && this.scrimEle.remove()
    }
    const itemList = Array.from(this.querySelectorAll("huanlin-nav-item"))
    itemList.forEach(item => {
      item.collapse = this.collapse
    })
  }

  handleFocusFirstItem = () => {
    const item = this.querySelector("huanlin-nav-item") as NavItem
    item && item?.setFocus()
  }
}
